import type { Completion } from '@codemirror/autocomplete';
import { Language } from '@codemirror/language';
import type { Extension } from '@codemirror/state';
import { AutocompleteProvider } from '../auto-completion/autocompletion.extension.js';
import type { ListAutocompletionConfig } from '../auto-completion/list/list-autocompletion-types.js';
/**
 * @internal
 */
export interface AutocompletionOptions {
    /** Activates autocomplete on typing */
    activateOnTyping: boolean;
    /** Adds additional CSS classes to completion options. */
    optionClass?: (completion: Completion) => string;
    /** Providers for autocomplete sources */
    providers: Array<AutocompleteProvider | ListAutocompletionConfig>;
}
/**
 * @internal
 */
export interface EditorLanguageConfiguration {
    language?: Language;
    extendWith?: readonly Extension[];
    autocompleteOptions?: AutocompletionOptions;
}
